/// <summary>
///
/// </summary>
/// <param name="_sender"></param>
/// <param name="_eventArgs"></param>
[DataEventHandler(tableStr(SalesAgreementLineEntity), DataEventType::PostedLoad)]
public static void SalesAgreementLineEntity_onPostedLoad(Common _sender, DataEventArgs _eventArgs)
{
    SalesAgreementLineEntity salesAgreementLineEntity = _sender as SalesAgreementLineEntity;

    AgreementHeaderDefault agreementHeaderDefault;
    ETG_SalesAgreementHeader ETG_SalesAgreementHeaderOrg;
    LogisticsPostalAddress logisticsPostalAddress, logisticsPostalAddressLoc,logisticsPostalAddressbank,logisticsPostalAddressseller;
    AgreementLine agreementLineOrg;
    PaymTerm paymTerm;
    InventTable inventTable;
    CustTable custTable;
    CompanyInfo companyInfo;
    BankAccountTable BankAccountTable,BankAccountTablebuyer;
    CustBankAccount custBankAccount;
    SalesAgreementHeader SalesAgreementHeader;
    salestable salestable;
    ETG_SALESTABLETRADE  ETG_SALESTABLETRADE; 
    ETG_CommodityMappingTable ETG_CommodityMappingTable;
    ETG_PlaceOfDischarge ETGPlaceOfDischargeCountry;
    ETG_PlaceOfLoading ETGPlaceOfLoadingCountry;

    select * from agreementHeaderDefault
        where agreementHeaderDefault.AgreementHeader == salesAgreementLineEntity.Agreement;

    salesAgreementLineEntity.DeliveryMode = agreementHeaderDefault.DeliveryMode;
    salesAgreementLineEntity.DeliveryTerm = agreementHeaderDefault.DeliveryTerm;
    salesAgreementLineEntity.PaymentTerms = agreementHeaderDefault.PaymentTerms;
    salesAgreementLineEntity.ETGReference  = agreementHeaderDefault.ExternalReference;
    select * from paymTerm
        where paymTerm.PaymTermId == salesAgreementLineEntity.PaymentTerms;

    salesAgreementLineEntity.PaymemtTermsDescription = paymTerm.Description;
    salesAgreementLineEntity.PaymTermTxt = paymTerm.PaymTermTxt;

    select * from ETG_SalesAgreementHeaderOrg
        where ETG_SalesAgreementHeaderOrg.SalesAgreementId == salesAgreementLineEntity.SalesAgreementId;

    salesAgreementLineEntity.BuyerBank = ETG_SalesAgreementHeaderOrg.BuyerBank;
    salesAgreementLineEntity.SellerBank = ETG_SalesAgreementHeaderOrg.SellerBank;
    salesAgreementLineEntity.PortOfLoading = ETG_SalesAgreementHeaderOrg.PortOfLoading;
    salesAgreementLineEntity.PortOfDischarge = ETG_SalesAgreementHeaderOrg.PortOfDischarge;
    salesAgreementLineEntity.PortOfLoadingDesc = ETG_SalesAgreementHeaderOrg.PortOfLoadingDesc;
    salesAgreementLineEntity.PortOfDischargeDesc = ETG_SalesAgreementHeaderOrg.PortOfDischargeDesc;

    select * from ETGPlaceOfDischargeCountry
        where ETGPlaceOfDischargeCountry.PlaceOfDischarge == salesAgreementLineEntity.PortOfDischarge;

    salesAgreementLineEntity.ETGPlaceOfDischargeCountry = ETGPlaceOfDischargeCountry.Country;

    select * from ETGPlaceOfLoadingCountry
        where ETGPlaceOfLoadingCountry.PlaceOfLoading == salesAgreementLineEntity.PortOfLoading;

    salesAgreementLineEntity.ETGPlaceOfLoadingCountry = ETGPlaceOfLoadingCountry.Country;

    salesAgreementLineEntity.BuyyerAccountNum = ETG_SalesAgreementHeaderOrg.BuyerAccountNum;
    salesAgreementLineEntity.BuyyerName = ETG_SalesAgreementHeaderOrg.buyerName();
    salesAgreementLineEntity.SellerAccountNum = ETG_SalesAgreementHeaderOrg.SellerAccountNum;
    salesAgreementLineEntity.SellerName = ETG_SalesAgreementHeaderOrg.sellerName();

    salesAgreementLineEntity.Notifytodifferentparty = ETG_SalesAgreementHeaderOrg.Notifytodifferentparty;
    salesAgreementLineEntity.NotifyPartyName = ETG_SalesAgreementHeaderOrg.Name;
    salesAgreementLineEntity.NotifyPartyAddress = ETG_SalesAgreementHeaderOrg.Address;
    salesAgreementLineEntity.Shipment = ETG_SalesAgreementHeaderOrg.DeliveryDescription;
    salesAgreementLineEntity.PackingGroup = ETG_SalesAgreementHeaderOrg.PackingGroup;
    salesAgreementLineEntity.PackingNotes = ETG_SalesAgreementHeaderOrg.Notes;
    salesAgreementLineEntity.Through = ETG_SalesAgreementHeaderOrg.Through;
    salesAgreementLineEntity.Consignee = ETG_SalesAgreementHeaderOrg.Consignee;
    salesAgreementLineEntity.ShipmentFrom = ETG_SalesAgreementHeaderOrg.FromDatePort;
    salesAgreementLineEntity.ShipmentTo = ETG_SalesAgreementHeaderOrg.ToDatePort;
    salesAgreementLineEntity.AgreementType = ETG_SalesAgreementHeaderOrg.AgreementType;
    salesAgreementLineEntity.Shipper = ETG_SalesAgreementHeaderOrg.ShipperBuyer;
    salesAgreementLineEntity.ETG_QuantityConditions  = ETG_SalesAgreementHeaderOrg.QuantityConditions;
    salesAgreementLineEntity.EtgFixation  = ETG_SalesAgreementHeaderOrg.Fixation;
    salesAgreementLineEntity.EtgCONTAINERID = ETG_SalesAgreementHeaderOrg.VESSELSAILED;

    salesAgreementLineEntity.ThroughName = VendTable::find(salesAgreementLineEntity.Through).name();

    select * from logisticsPostalAddress
        where logisticsPostalAddress.RecId == ETG_SalesAgreementHeaderOrg.BuyerDeliveryAddress;

    salesAgreementLineEntity.BuyyerBankAddress = logisticsPostalAddress.Address;
    salesAgreementLineEntity.BuyyerAddress = logisticsPostalAddress.Address;

    select * from logisticsPostalAddressLoc
        where logisticsPostalAddressLoc.RecId == ETG_SalesAgreementHeaderOrg.SellerDeliveryAddress;

    salesAgreementLineEntity.SellerBankAddress = logisticsPostalAddressLoc.Address;
    salesAgreementLineEntity.SellerAddress = logisticsPostalAddressLoc.Address;

    select * from agreementLineOrg
        where agreementLineOrg.Agreement == salesAgreementLineEntity.Agreement;

    salesAgreementLineEntity.ItemName = agreementLineOrg.name();
    salesAgreementLineEntity.PriceTxt = agreementLineOrg.ETGPriceCondition;
    salesAgreementLineEntity.ETGFinalPlaceOfDelivery = agreementLineOrg.ETGFinalPlaceOfDelivery;

    select * from inventTable
        where inventTable.ItemId == salesAgreementLineEntity.ItemNumber;

    salesAgreementLineEntity.ETGMainCommodity = inventTable.ETGCommodity;

    select firstonly ETG_CommodityMappingTable 
        where ETG_CommodityMappingTable.MainCommodity == inventTable.ETGCommodity;

    salesAgreementLineEntity.ETGCommodity = ETG_CommodityMappingTable.Commodity;

    select * from custTable
        where custTable.AccountNum == salesAgreementLineEntity.CustAccount;

    salesAgreementLineEntity.CustName = custTable.name();
    salesAgreementLineEntity.CustAddress = custTable.address();
    salesAgreementLineEntity.Email = CustTable::find(salesAgreementLineEntity.CustAccount).email();

    DirPartyTable       dirPartyTable;
    TaxInformation_IN   taxInformation_IN;
    DirPartyLocation    dirPartyLocation;
    TaxRegistration     taxRegistration;
    TaxRegistrationType taxRegistrationType;

    select * from dirPartyTable
        where dirPartyTable.RecId == custTable.Party;

    taxInformation_IN = TaxInformation_IN::findDefaultbyLocation(LogisticsPostalAddress::findRecId(dirPartyTable.PrimaryAddressLocation).Location);

    salesAgreementLineEntity.TIN = TaxRegistrationNumbers_IN::find(taxInformation_IN.TIN).RegistrationNumber;

    select * from companyInfo where companyInfo.DataArea == curExt();

    salesAgreementLineEntity.CompanyName = companyInfo.name();
    salesAgreementLineEntity.CompanyAddress = companyInfo.postalAddress().Address;

    salesAgreementLineEntity.CustCountryRegionId = custTable.postalAddress().CountryRegionId;

    select * from dirPartyLocation
        where dirPartyLocation.Party == dirPartyTable.RecId
        && dirPartyLocation.IsPrimary == NoYes::Yes;

    while select * from taxRegistration
        where taxRegistration.DirPartyLocation == dirPartyLocation.RecId
    {
        select * from taxRegistrationType
        where taxRegistrationType.RecId == taxRegistration.TaxRegistrationTypeApplicabilityRule;

        if(taxRegistrationType.TaxRegstrationType == "IEC")
        {
            salesAgreementLineEntity.ETGIECCode = taxRegistration.RegistrationNumber;
        }
        if(taxRegistrationType.TaxRegstrationType == "FSSAI")
        {
            salesAgreementLineEntity.ETGFSSAIID = taxRegistration.RegistrationNumber;
        }
        if(taxRegistrationType.TaxRegstrationType == "GST")
        {
            salesAgreementLineEntity.ETGGSTIN = taxRegistration.RegistrationNumber;
        }
        if(!salesAgreementLineEntity.ETGIECCode && taxRegistration.TaxRegistrationTypeApplicabilityRule == str2Int64("IEC"))
        {
            salesAgreementLineEntity.ETGIECCode = taxRegistration.RegistrationNumber;
        }
        if(!salesAgreementLineEntity.ETGFSSAIID && taxRegistration.TaxRegistrationTypeApplicabilityRule == str2Int64("FSSAI"))
        {
            salesAgreementLineEntity.ETGFSSAIID = taxRegistration.RegistrationNumber;
        }
        if(!salesAgreementLineEntity.ETGGSTIN && taxRegistration.TaxRegistrationTypeApplicabilityRule == str2Int64("GST"))
        {
            salesAgreementLineEntity.ETGGSTIN = taxRegistration.RegistrationNumber;
        }
    }
    if(!salesAgreementLineEntity.ETGIECCode)
    {
        salesAgreementLineEntity.ETGIECCode = custTable.ETGIECCode;
    }
    if(!salesAgreementLineEntity.ETGFSSAIID)
    {
        salesAgreementLineEntity.ETGFSSAIID = custTable.ETGFSSAIID;
    }
    if(!salesAgreementLineEntity.ETGGSTIN)
    {
        salesAgreementLineEntity.ETGGSTIN = custTable.ETGGSTIN;
    }
    select * from SalesAgreementHeader
        where SalesAgreementHeader.SalesNumberSequence == salesAgreementLineEntity.SalesAgreementId;
    select * from salestable where
             salestable.MatchingAgreement == SalesAgreementHeader.RecId;
    select * from  ETG_SALESTABLETRADE where
        ETG_SALESTABLETRADE.SalesId == salestable.SalesId;

      salesAgreementLineEntity.ETGSOType = ETG_SALESTABLETRADE.OrderType;

    select firstonly BankAccountTable where BankAccountTable.AccountID == salesAgreementLineEntity.SellerBank;


    salesAgreementLineEntity.ETGSellerBankName = BankAccountTable.Name;
    salesAgreementLineEntity.ETGIbanNumber = BankAccountTable.IBAN;
    salesAgreementLineEntity.ETGSwiftCode = BankAccountTable.SWIFTNo;
    salesAgreementLineEntity.ETGAccountNumber = BankAccountTable.AccountNum;
    salesAgreementLineEntity.ETGCorrespondingBank = BankAccountTable.ETGCorrespondentBank;

    select * from logisticsPostalAddressbank where logisticsPostalAddressbank.Location == BankAccountTable.Location;
    salesAgreementLineEntity.SellerBankAddress = logisticsPostalAddressbank.Address;

    select firstonly custBankAccount where custBankAccount.AccountID == salesAgreementLineEntity.BuyerBank
                                        && custBankAccount.CustAccount == salesAgreementLineEntity.CustAccount;


    // salesAgreementLineEntity.ETGSellerBankName = BankAccountTablebuyer.Name;
    salesAgreementLineEntity.ETGBuyerBankName = custBankAccount.Name;
    salesAgreementLineEntity.ETGIbanNumberBuyer = custBankAccount.BankIBAN;
    salesAgreementLineEntity.ETGSwiftCodeBuyer = custBankAccount.SWIFTNo;
    salesAgreementLineEntity.ETGAccountNumberbuyer = custBankAccount.AccountNum;
    salesAgreementLineEntity.ETGIfsc = custBankAccount.ETGIfsc;
  //  salesAgreementLineEntity.ETGCorrespondingBankbuyer = custBankAccount.corr;

    select * from logisticsPostalAddressseller where logisticsPostalAddressseller.Location == custBankAccount.Location;
    salesAgreementLineEntity.BuyyerBankAddress = logisticsPostalAddressseller.Address;

    if(!salesAgreementLineEntity.BuyyerBankAddress)
    {
        select * from logisticsPostalAddressseller where logisticsPostalAddressseller.Location == str2Int64(custBankAccount.AccountID);
        salesAgreementLineEntity.BuyyerBankAddress = logisticsPostalAddressseller.Address;
    }

}
